const LIST_STATUS_ICON_MAP: Record<ListStatus, ComponentType<IconProps>> = {
  planned: IconStatusPlanned,
  watching: IconStatusCurrent,
  completed: IconStatusCompleted,
  onHold: IconStatusPaused,
  dropped: IconStatusDropped,
  rewatching: IconRepeat,
}

/** Типы медиа, для которых «смотрю» = играю (status-play). */
const WATCHING_AS_PLAY_TYPES = new Set<string>(['game'])
/** Типы медиа, для которых «смотрю» = читаю (status-reading). */
const WATCHING_AS_READING_TYPES = new Set<string>(['book', 'manga', 'light-novel'])

/** Возвращает компонент иконки для статуса списка. Для игр при «смотрю» — status-play, для книг/манги/ранобэ — status-reading. */
export function getListStatusIcon(status: ListStatus, mediaType?: string): ComponentType<IconProps> {
  if (status === 'watching' && mediaType) {
    if (WATCHING_AS_PLAY_TYPES.has(mediaType)) return IconStatusPlay
    if (WATCHING_AS_READING_TYPES.has(mediaType)) return IconStatusReading
  }
  return LIST_STATUS_ICON_MAP[status]
}

/** Опции для бейджа статуса: singleColor — один цвет для всех (например в профиле). */
export type ListStatusBadgeOptions = { singleColor?: boolean }

/** Цвета фона и текста бейджа иконки статуса. Один вариант на статус: planned, watching (смотрю/играю/читаю), completed, onHold, dropped, rewatching. Если options.singleColor === true — один общий цвет для всех. */
export function getListStatusBadgeClasses(
  status: ListStatus,
  _mediaType?: string,
  options?: ListStatusBadgeOptions
): { bg: string; text: string } {
  const darkText = 'text-thistle-100 dark:text-thistle-900'
  const singleColor = options?.singleColor
  if (singleColor) {
    return { bg: 'bg-thistle-400/90 dark:bg-thistle-500/90', text: darkText }
  }
  switch (status) {
    case 'planned':
      return { bg: 'bg-thistle-400/90 dark:bg-thistle-500/90', text: darkText }
    case 'watching':
      return { bg: 'bg-lavender-400/90 dark:bg-lavender-500/90', text: darkText }
    case 'completed':
      return { bg: 'bg-lavender_veil-500/95 dark:bg-lavender_veil-600/95', text: darkText }
    case 'onHold':
      return { bg: 'bg-lavender_grey-400/90 dark:bg-lavender_grey-500/90', text: darkText }
    case 'dropped':
      return { bg: 'bg-soft_blush-400/90 dark:bg-soft_blush-500/90', text: darkText }
    case 'rewatching':
      return { bg: 'bg-thistle-500/90 dark:bg-thistle-600/90', text: darkText }
    default:
      return { bg: 'bg-thistle-400/90 dark:bg-thistle-500/90', text: darkText }
  }
}
